export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  // Normalize and remove diacritics, keep Unicode letters and numbers
  const normalized = s.normalize("NFKD").replace(/\p{M}/gu, "");
  const slug = normalized
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, "-")
    .replace(/(^-|-$)+/g, "");
  return slug;
}

export function truncate(input, maxLength = 80, suffix = "…") {
  const s = toStr(input);
  if (!s) return "";
  const max = Math.max(0, Number(maxLength) || 0);
  const suf = toStr(suffix);
  if (s.length <= max) return s;
  if (max === 0) return "";
  const cutoff = Math.max(0, max - suf.length);
  if (cutoff <= 0) return suf.slice(0, max);
  let piece = s.slice(0, cutoff);
  const lastSpace = piece.lastIndexOf(" ");
  if (lastSpace > 0) {
    piece = piece.slice(0, lastSpace);
  }
  return piece + suf;
}

export function camelCase(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  const parts = s.split(/[^0-9\p{L}]+/u).filter(Boolean);
  if (parts.length === 0) return "";
  const first = parts[0].toLowerCase();
  const rest = parts
    .slice(1)
    .map((p) => p.charAt(0).toUpperCase() + p.slice(1).toLowerCase())
    .join("");
  return first + rest;
}

export function kebabCase(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  // Handle camelCase boundaries first
  const withBoundaries = s.replace(/([a-z0-9])([A-Z])/g, "$1-$2");
  const parts = withBoundaries.split(/[^0-9\p{L}]+/u).filter(Boolean);
  return parts.map((p) => p.toLowerCase()).join("-");
}

export function titleCase(input) {
  const s = toStr(input);
  if (!s) return "";
  return s
    .split(/(\s+)/)
    .map((token) => {
      if (token.trim() === "") return token;
      return token.charAt(0).toUpperCase() + token.slice(1).toLowerCase();
    })
    .join("");
}

export function wordWrap(input, width = 80) {
  const s = toStr(input);
  if (!s) return "";
  const w = Math.max(1, Number(width) || 80);
  const words = s.split(/\s+/).filter(Boolean);
  const lines = [];
  let line = "";
  for (const word of words) {
    if (line.length === 0) {
      // start a new line
      if (word.length > w) {
        // long word on its own line
        lines.push(word);
      } else {
        line = word;
      }
    } else {
      if (line.length + 1 + word.length <= w) {
        line = line + " " + word;
      } else {
        lines.push(line);
        if (word.length > w) {
          lines.push(word);
          line = "";
        } else {
          line = word;
        }
      }
    }
  }
  if (line.length > 0) lines.push(line);
  return lines.join("\n");
}

export function stripHtml(input) {
  let s = toStr(input);
  if (!s) return "";
  // Remove script/style
  s = s.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, "");
  s = s.replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, "");
  // Remove tags
  s = s.replace(/<[^>]+>/g, "");
  // Decode common entities
  const map = {
    "&amp;": "&",
    "&lt;": "<",
    "&gt;": ">",
    "&quot;": '"',
    "&#39;": "'",
    "&nbsp;": " ",
  };
  s = s.replace(/&[a-zA-Z0-9#]+;/g, (ent) => {
    if (map[ent]) return map[ent];
    if (ent.startsWith("&#x") || ent.startsWith("&#X")) {
      const num = parseInt(ent.slice(3, -1), 16);
      if (!Number.isNaN(num)) return String.fromCodePoint(num);
    }
    if (ent.startsWith("&#")) {
      const num = parseInt(ent.slice(2, -1), 10);
      if (!Number.isNaN(num)) return String.fromCodePoint(num);
    }
    return ent;
  });
  return s;
}

export function escapeRegex(input) {
  const s = toStr(input);
  if (!s) return "";
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function pluralize(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  const lower = s.toLowerCase();
  if (/(s|x|z|ch|sh)$/i.test(lower)) return s + "es";
  if (/[bcdfghjklmnpqrstvwxyz]y$/i.test(lower)) return s.slice(0, -1) + "ies";
  if (/(?:fe|f)$/i.test(lower)) return s.replace(/(?:fe|f)$/i, "ves");
  return s + "s";
}

export function levenshtein(a, b) {
  const A = Array.from(toStr(a));
  const B = Array.from(toStr(b));
  const n = A.length;
  const m = B.length;
  if (n === 0) return m;
  if (m === 0) return n;
  // Use two-row DP to save memory
  let prev = new Array(m + 1);
  let cur = new Array(m + 1);
  for (let j = 0; j <= m; j++) prev[j] = j;
  for (let i = 1; i <= n; i++) {
    cur[0] = i;
    for (let j = 1; j <= m; j++) {
      const cost = A[i - 1] === B[j - 1] ? 0 : 1;
      cur[j] = Math.min(
        prev[j] + 1, // deletion
        cur[j - 1] + 1, // insertion
        prev[j - 1] + cost // substitution
      );
    }
    const tmp = prev;
    prev = cur;
    cur = tmp;
  }
  return prev[m];
}
